mapper.select:
select b.work_proc_id
from   TB_WORK_ORDER_BATCH a
           inner join TB_WORK_ORDER_PROC b
                      on b.proc_cd = #{procCd}
                          and  b.work_batch_id = a.work_batch_id
where  a.work_batch_id = #{workBatchId}

mapper.update:
update TB_WORK_ORDER_PROC
set    proc_status          = #{procStatus}
      ,storage_cd           = #{storageCd}
      ,work_equipment_Cd    = #{workEquipmentCd}
      ,prod_date            = convert(date, getdate(), -23)
      ,work_start_time      = getDate()
      ,test_no              = #{testNo}
      ,upd_id               = #{userId}
      ,upd_dt               = getDate()
where  work_proc_id         = #{workProcId}

update TB_WORK_ORDER_PROC
set    proc_status      = #{procStatus}
      ,in_tran_id       = #{inTranId}
      ,work_end_time    = getDate()
      ,upd_id           = #{userId}
      ,upd_dt           = getDate()
where  work_proc_id     = #{workProcId}

update TB_WORK_ORDER_PROC
set    prod_qty      = #{prodQty}
      ,etc           = #{etc}
      ,upd_id        = #{userId}
      ,upd_dt        = getDate()
where  work_proc_id  = #{workProcId}

update tb_weigh_info
set    maker       = #{maker}
      ,make_Qty    = #{makeQty}
      ,upd_id      = #{userId}
      ,upd_dt      = getDate()
where  weigh_id    = #{weighId}

update tb_make_etc
set    bom_ver  =  #{bomVer}
      ,maker    = #{maker}
      ,confirmer = #{confirmer}
      ,process_Time = #{processTime}
      ,mat_Proc = #{matProc}
      ,manipulate = #{manipulate}
      ,significant = #{significant}
      ,note     = #{note}
      ,filter_cnt = #{filterCnt}
      ,filter_Type = #{filterType}
      ,filter_Damage = #{filterDamage}
      ,substance_check = #{substanceCheck}
      ,upd_id  = #{userId}
      ,upd_dt = getDate()
where  work_proc_id = #{workProcId}

update TB_WORK_ORDER_PROC
set    proc_status = #{procStatus}
      ,work_end_time = getDate()
      ,tran_yn      = 'Y'
      ,tran_id       = #{tranId}
      ,upd_id       = #{userId}
      ,upd_dt       = getdate()
where  work_proc_id = #{workProcId}
